        const totalBilled = db.prepare("SELECT SUM(total) as value FROM invoices WHERE issueDate >= date('now', '-30 days')").get().value || 0;
        const totalCollected = db.prepare("SELECT SUM(amount) as value FROM payments WHERE date >= date('now', '-30 days')").get().value || 0;
