        // Revenue Chart (last 6 months)
        const revenueData = db.prepare(`
            WITH RECURSIVE months(m) AS (
                SELECT date('now', 'start of month')
                UNION ALL
                SELECT date(m, '-1 month') FROM months WHERE m > date('now', 'start of month', '-5 months')
            )
            SELECT
                strftime('%b', m) as month,
                (SELECT IFNULL(SUM(total), 0) FROM invoices WHERE strftime('%Y-%m', issueDate) = strftime('%Y-%m', m)) as billed,
                (SELECT IFNULL(SUM(amount), 0) FROM payments WHERE strftime('%Y-%m', date) = strftime('%Y-%m', m)) as collected
            FROM months ORDER BY m ASC
        `).all();

        // Debt Aging
        const agingData = [
            { name: '0-30 Days', value: db.prepare("SELECT SUM(total) as v FROM invoices WHERE status = 'Due' AND dueDate >= date('now', '-30 days')").get().v || 0, fill: '#3b82f6' },
