app.get('/api/customers', (req, res) => {
    const { q, sortKey, sortDir, page = 1, limit = 10 } = req.query;
    let query = 'SELECT * FROM customers';
    const params = [];

    if (q) {
        query += ' WHERE name LIKE ? OR accountNumber LIKE ? OR email LIKE ?';
        params.push(`%${q}%`, `%${q}%`, `%${q}%`);
    }

    if (sortKey && sortDir) {
        const allowedKeys = ['name', 'accountNumber', 'email', 'address', 'joinDate'];
        if (allowedKeys.includes(sortKey)) {
            query += ` ORDER BY ${sortKey} ${sortDir === 'descending' ? 'DESC' : 'ASC'}`;
        }
    } else {
         query += ` ORDER BY joinDate DESC`;
    }

    const totalStmt = db.prepare(query.replace('SELECT *', 'SELECT COUNT(*) as count')).all(...params);
    const totalItems = totalStmt[0].count;

    if (limit !== '1000') {
        query += ' LIMIT ? OFFSET ?';
        params.push(parseInt(limit), (parseInt(page) - 1) * parseInt(limit));
    }

    const customers = db.prepare(query).all(...params);
    res.json({ customers, totalItems });
});

app.get('/api/customers/:id', (req, res) => {
    try {
        const customer = db.prepare('SELECT * FROM customers WHERE id = ?').get(req.params.id);
        if (!customer) {
            return res.status(404).json({ message: 'Customer not found' });
        }

        const invoices = db.prepare('SELECT * FROM invoices WHERE customerAccount = ? ORDER BY issueDate DESC').all(customer.accountNumber);
        const payments = db.prepare('SELECT * FROM payments WHERE customerName = ? ORDER BY date DESC').all(customer.name);

        const balanceResult = db.prepare("SELECT SUM(total) as totalDue FROM invoices WHERE customerAccount = ? AND status IN ('Due', 'Overdue')").get(customer.accountNumber);
        const outstandingBalance = balanceResult.totalDue || 0;

        res.json({ 
            customer, 
            history: { invoices, payments },
            outstandingBalance,
            lastUpdated: new Date().toISOString(),
        });

    } catch (err) {
        res.status(500).json({ message: 'Failed to fetch customer details', error: err.message });
    }
});


