    if (status && status !== 'all') {
        conditions.push('status = ?');
        params.push(status);
    }

    if (conditions.length > 0) {
        query += ' WHERE ' + conditions.join(' AND ');
    }

    query += ' ORDER BY installationDate DESC';

    const meters = db.prepare(query).all(...params);
