import React, { useState, useEffect, useRef } from 'react';
import { DashboardIcon, UsersIcon, FileTextIcon, CreditCardIcon, BarChartIcon, SettingsIcon, DropletIcon, LogoIcon, ChevronLeftIcon, ChevronDownIcon, UserIcon } from './icons';

interface SidebarProps {
  sidebarOpen: boolean;
  setSidebarOpen: (open: boolean) => void;
  activeView: string;
  setActiveView: (view: string) => void;
}

const NavLink = ({ item, activeView, setActiveView, setSidebarOpen, sidebarExpanded }: any) => {
    const isActive = activeView === item.label;
    return (
        <button
            onClick={() => {
                setActiveView(item.label);
                setSidebarOpen(false);
            }}
            className={`group relative flex items-center gap-2.5 rounded-lg px-4 py-2 font-medium w-full text-left duration-300 ease-in-out hover:bg-slate-800/50 ${isActive ? 'bg-blue-600/30 text-white' : 'text-slate-300 hover:text-white'}`}
        >
            <item.icon className={`h-5 w-5 ${isActive ? 'text-white' : 'text-slate-400 group-hover:text-white'}`} />
            <span className={`text-slate-200 group-hover:text-white ${!sidebarExpanded && 'hidden'}`}>{item.label}</span>
        </button>
    );
};

const NavGroup = ({ group, activeView, setActiveView, setSidebarOpen, sidebarExpanded }: any) => {
    const [isOpen, setIsOpen] = useState(false);

    const isActiveGroup = group.items.some((item: any) => item.label === activeView);

    useEffect(() => {
        if(isActiveGroup) {
            setIsOpen(true);
        }
    }, [isActiveGroup]);


    return (
        <div className="py-2">
            <button 
                onClick={() => sidebarExpanded && setIsOpen(!isOpen)} 
                className="group relative flex items-center justify-between gap-2.5 rounded-lg px-4 py-2 font-medium w-full text-left duration-300 ease-in-out hover:bg-slate-800/50"
            >
                <div className="flex items-center gap-2.5">
                    <group.icon className={`h-5 w-5 ${isActiveGroup ? 'text-white' : 'text-slate-400 group-hover:text-white'}`} />
                    <span className={`text-slate-200 group-hover:text-white ${!sidebarExpanded && 'hidden'}`}>{group.label}</span>
                </div>
                {sidebarExpanded && <ChevronDownIcon className={`w-4 h-4 text-slate-400 transition-transform ${isOpen && 'rotate-180'}`} />}
            </button>
            {sidebarExpanded && isOpen && (
                <div className="mt-2 ml-6 space-y-1 border-l border-slate-700 pl-4">
                    {group.items.map((item: any) => (
                        <li key={item.label}>
                           <NavLink item={item} activeView={activeView} setActiveView={setActiveView} setSidebarOpen={setSidebarOpen} sidebarExpanded={sidebarExpanded} />
                        </li>
                    ))}
                </div>
            )}
        </div>
    );
};

const Sidebar: React.FC<SidebarProps> = ({ sidebarOpen, setSidebarOpen, activeView, setActiveView }) => {
  const [sidebarExpanded, setSidebarExpanded] = useState(true);

  const trigger = useRef<HTMLButtonElement>(null);
  const sidebar = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const clickHandler = ({ target }: MouseEvent) => {
      if (!sidebar.current || !trigger.current) return;
      if (!sidebarOpen || sidebar.current.contains(target as Node) || trigger.current.contains(target as Node)) return;
      setSidebarOpen(false);
    };
    document.addEventListener('click', clickHandler);
    return () => document.removeEventListener('click', clickHandler);
  });

  const navItems = [
    {
        title: 'MENU',
        links: [
            { icon: DashboardIcon, label: 'Dashboard' },
            { icon: BarChartIcon, label: 'Reports' },
        ]
    },
    {
        title: 'MANAGEMENT',
        links: [
            { icon: UsersIcon, label: 'Customers' },
            { icon: DropletIcon, label: 'Meters & Readings' },
            { 
                label: 'Billing',
                icon: FileTextIcon,
                items: [
                    { icon: FileTextIcon, label: 'Invoices' },
                    { icon: CreditCardIcon, label: 'Payments' },
                ]
            }
        ]
    },
    {
        title: 'SYSTEM',
        links: [
             { icon: UserIcon, label: 'Users' },
             { icon: SettingsIcon, label: 'Settings' },
        ]
    }
  ];

  return (
     <aside
      ref={sidebar}
      className={`absolute left-0 top-0 z-50 flex h-screen flex-col overflow-y-hidden bg-slate-900/90 backdrop-blur-lg text-slate-200 duration-300 ease-linear lg:static lg:translate-x-0 ${
        sidebarOpen ? 'translate-x-0' : '-translate-x-full'
      } ${sidebarExpanded ? 'w-72' : 'w-20'}`}
    >
      <div className="flex items-center justify-between gap-2 px-6 py-5.5 lg:py-6.5">
        <a href="#" className={`flex items-center gap-2 ${!sidebarExpanded && 'justify-center w-full'}`}>
            <LogoIcon className="h-9 w-9 text-blue-500" />
            <span className={`text-2xl font-bold ${!sidebarExpanded && 'hidden'}`}>Splash & Dash</span>
        </a>
        <button
            onClick={() => setSidebarExpanded(!sidebarExpanded)}
            className="hidden lg:block p-1.5 rounded-full bg-slate-800 hover:bg-slate-700"
        >
            <ChevronLeftIcon className={`w-5 h-5 transition-transform duration-300 ${!sidebarExpanded && 'rotate-180'}`} />
        </button>
      </div>

      <div className="flex flex-col overflow-y-auto duration-300 ease-linear">
        <nav className="mt-5 px-4 lg:px-6">
            {navItems.map((group) => (
                <div key={group.title}>
                    <h3 className={`mb-4 ml-4 text-sm font-semibold text-slate-400 ${!sidebarExpanded && 'hidden'}`}>{group.title}</h3>
                    <ul className="mb-6 flex flex-col gap-1.5">
                    {group.links.map((item) => (
                        <li key={item.label}>
                            {'items' in item ? (
                                <NavGroup group={item} activeView={activeView} setActiveView={setActiveView} setSidebarOpen={setSidebarOpen} sidebarExpanded={sidebarExpanded} />
                            ) : (
                                <NavLink item={item} activeView={activeView} setActiveView={setActiveView} setSidebarOpen={setSidebarOpen} sidebarExpanded={sidebarExpanded} />
                            )}
                        </li>
                    ))}
                    </ul>
                </div>
            ))}
        </nav>
      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import Dashboard from './components/Dashboard';
import Toast from './components/Toast';
import Meters from './components/Meters';
import Settings from './components/Settings';
import Customers from './components/Customers';
import Invoices from './components/Invoices';
import Reports from './components/Reports';
import Payments from './components/Payments';
import Users from './components/Users';
import LoadingScreen from './components/LoadingScreen';

const App: React.FC = () => {
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [activeView, setActiveView] = useState('Dashboard');
  const [loading, setLoading] = useState(true);
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(() => {
    return localStorage.getItem('theme') === 'dark' || 
           (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches);
  });

  useEffect(() => {
    const timer = setTimeout(() => setLoading(false), 2500);
    return () => clearTimeout(timer);
  }, []);

  useEffect(() => {
    if (isDarkMode) {
        document.documentElement.classList.add('dark');
        document.body.classList.add('dark-mode-bg');
        document.body.classList.remove('light-mode-bg');
        localStorage.setItem('theme', 'dark');
    } else {
        document.documentElement.classList.remove('dark');
        document.body.classList.add('light-mode-bg');
        document.body.classList.remove('dark-mode-bg');
        localStorage.setItem('theme', 'light');
    }
  }, [isDarkMode]);


  const showToast = (message: string, type: 'success' | 'error' = 'success') => {
    setToast({ message, type });
  };

  const closeToast = () => {
    setToast(null);
  }

  const renderContent = () => {
    switch (activeView) {
      case 'Dashboard':
        return <Dashboard setActiveView={setActiveView} />;
      case 'Customers':
        return <Customers showToast={showToast} />;
      case 'Meters & Readings':
        return <Meters showToast={showToast} />;
      case 'Invoices':
        return <Invoices showToast={showToast} />;
      case 'Payments':
        return <Payments showToast={showToast} />;
      case 'Reports':
        return <Reports />;
      case 'Users':
        return <Users showToast={showToast} />;
      case 'Settings':
        return <Settings showToast={showToast} />;
      default:
        return <Dashboard setActiveView={setActiveView} />;
    }
  }

  if (loading) {
    return <LoadingScreen />;
  }

  return (
    <div className="text-slate-800 dark:text-slate-50">
      <div className="flex h-screen overflow-hidden">
        <Sidebar 
          sidebarOpen={sidebarOpen} 
          setSidebarOpen={setSidebarOpen} 
          activeView={activeView}
          setActiveView={setActiveView}
        />

        <div className="relative flex flex-1 flex-col overflow-y-auto overflow-x-hidden">
          <Header 
            sidebarOpen={sidebarOpen} 
            setSidebarOpen={setSidebarOpen} 
            activeView={activeView}
            showToast={showToast}
            isDarkMode={isDarkMode}
            setIsDarkMode={setIsDarkMode}
          />

          <main className="flex-grow">
            <div className="mx-auto max-w-screen-2xl p-4 md:p-6 2xl:p-10">
              {renderContent()}
            </div>
          </main>
        </div>
        {toast && <Toast message={toast.message} type={toast.type} onClose={closeToast} />}
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useCallback } from 'react';
import { User, UserFormData } from '../types';
import { UserPlusIcon, Trash2Icon, ShieldCheckIcon } from './icons';
import { fetchFromApi } from '../lib/api';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from './ui/Card';
import { Button } from './ui/Button';
import AddUserForm from './AddUserForm';

interface UsersProps {
    showToast: (message: string, type?: 'success' | 'error') => void;
}

const Users: React.FC<UsersProps> = ({ showToast }) => {
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState<string | null>(null);
    const [isAddingUser, setIsAddingUser] = useState(false);

    const fetchUsers = useCallback(async () => {
        setLoading(true);
        try {
            const data = await fetchFromApi('users');
            setUsers(data || []);
            setError(null);
        } catch (err: any) {
            setError(err.message || 'Failed to fetch users.');
            showToast(err.message || 'Failed to fetch users.', 'error');
        } finally {
            setLoading(false);
        }
    }, [showToast]);

    useEffect(() => {
        fetchUsers();
    }, [fetchUsers]);

    const handleSaveUser = async (data: UserFormData) => {
        try {
            await fetchFromApi('users', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(data),
            });
            showToast('User created successfully!', 'success');
            setIsAddingUser(false);
            fetchUsers();
        } catch (err: any) {
            showToast(err.message || 'Failed to create user.', 'error');
        }
    };

    const handleDeleteUser = async (id: string) => {
        if (!window.confirm('Are you sure you want to remove this user?')) return;
        try {
            await fetchFromApi(`users/${id}`, { method: 'DELETE' });
            showToast('User removed.', 'success');
            fetchUsers();
        } catch (err: any) {
            showToast(err.message || 'Failed to delete user.', 'error');
        }
    };

    const getRoleBadgeColor = (role: string) => {
        switch (role) {
            case 'Admin': return 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300';
            case 'Manager': return 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300';
            case 'Agent': return 'bg-emerald-100 text-emerald-800 dark:bg-emerald-900/30 dark:text-emerald-300';
            default: return 'bg-slate-100 text-slate-800';
        }
    };

    return (
        <div className="space-y-6">
            <Card>
                <CardHeader>
                    <div className="flex justify-between items-center">
                        <div>
                            <CardTitle>System Users</CardTitle>
                            <CardDescription>Manage administrative staff and their permissions.</CardDescription>
                        </div>
                        <Button variant="primary" onClick={() => setIsAddingUser(true)}>
                            <UserPlusIcon className="h-4 w-4 mr-2" />
                            Add System User
                        </Button>
                    </div>
                </CardHeader>
                <CardContent>
                    {loading ? (
                        <div className="text-center py-10 text-slate-500">Loading system users...</div>
                    ) : error ? (
                        <div className="text-center py-10 text-red-500">{error}</div>
                    ) : (
                        <div className="overflow-x-auto">
                            <table className="w-full text-sm text-left">
                                <thead className="text-xs text-slate-700 uppercase bg-slate-50 dark:bg-slate-800/50 dark:text-slate-400">
                                    <tr>
                                        <th className="px-6 py-4">Name</th>
                                        <th className="px-6 py-4">Email</th>
                                        <th className="px-6 py-4">Role</th>
                                        <th className="px-6 py-4">Last Active</th>
                                        <th className="px-6 py-4 text-right">Actions</th>
                                    </tr>
                                </thead>
                                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                                    {users.map(user => (
                                        <tr key={user.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors">
                                            <td className="px-6 py-4 font-medium flex items-center gap-2 text-slate-900 dark:text-white">
                                                <div className="w-8 h-8 rounded-full bg-slate-200 dark:bg-slate-700 flex items-center justify-center text-xs">
                                                    {user.name.split(' ').map(n => n[0]).join('')}
                                                </div>
                                                {user.name}
                                            </td>
                                            <td className="px-6 py-4 text-slate-500">{user.email}</td>
                                            <td className="px-6 py-4">
                                                <span className={`px-2.5 py-0.5 rounded-full text-xs font-bold ${getRoleBadgeColor(user.role)}`}>
                                                    {user.role}
                                                </span>
                                            </td>
                                            <td className="px-6 py-4 text-slate-500 text-xs">
                                                {new Date(user.lastActive).toLocaleDateString()}
                                            </td>
                                            <td className="px-6 py-4 text-right">
                                                <button 
                                                    onClick={() => handleDeleteUser(user.id)}
                                                    className="p-2 text-red-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-lg transition-colors"
                                                >
                                                    <Trash2Icon className="h-4 w-4" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))}
                                </tbody>
                            </table>
                        </div>
                    )}
                </CardContent>
            </Card>

            {isAddingUser && (
                <AddUserForm 
                    onSave={handleSaveUser} 
                    onCancel={() => setIsAddingUser(false)} 
                />
            )}
        </div>
    );
};

export default Users;

import React, { useState, useMemo } from 'react';
import { userSchema, UserFormData } from '../lib/schemas';
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from './ui/Card';
import { Input } from './ui/Input';
import { Button } from './ui/Button';
import Modal from './ui/Modal';

interface AddUserFormProps {
    onSave: (data: UserFormData) => void;
    onCancel: () => void;
}

const AddUserForm: React.FC<AddUserFormProps> = ({ onSave, onCancel }) => {
    const [formData, setFormData] = useState<UserFormData>({
        name: '',
        email: '',
        role: 'Agent',
    });
    const [errors, setErrors] = useState<{ [key: string]: string | undefined }>({});

    const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
        if (errors[name]) {
            setErrors(prev => ({ ...prev, [name]: undefined }));
        }
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        const result = userSchema.safeParse(formData);
        if (!result.success) {
            const newErrors: { [key: string]: string } = {};
            result.error.issues.forEach(issue => {
                if (typeof issue.path[0] === 'string') {
                    newErrors[issue.path[0]] = issue.message;
                }
            });
            setErrors(newErrors);
        } else {
            onSave(result.data);
        }
    };

    const isFormValid = useMemo(() => userSchema.safeParse(formData).success, [formData]);

    return (
        <Modal title="Create System User" onClose={onCancel} className="max-w-md">
            <form onSubmit={handleSubmit}>
                <div className="p-6 space-y-4">
                    <div>
                        <label htmlFor="name" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Full Name</label>
                        <Input 
                            type="text" 
                            name="name" 
                            id="name" 
                            value={formData.name} 
                            onChange={handleChange}
                            placeholder="e.g. John Doe"
                            className={errors.name ? 'border-red-500' : ''}
                        />
                        {errors.name && <p className="mt-1 text-xs text-red-500">{errors.name}</p>}
                    </div>

                    <div>
                        <label htmlFor="email" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Work Email</label>
                        <Input 
                            type="email" 
                            name="email" 
                            id="email" 
                            value={formData.email} 
                            onChange={handleChange}
                            placeholder="john@splashdash.co.ke"
                            className={errors.email ? 'border-red-500' : ''}
                        />
                        {errors.email && <p className="mt-1 text-xs text-red-500">{errors.email}</p>}
                    </div>

                    <div>
                        <label htmlFor="role" className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Access Role</label>
                        <select 
                            id="role" 
                            name="role" 
                            value={formData.role} 
                            onChange={handleChange}
                            className="flex h-10 w-full rounded-md border border-slate-300 bg-white dark:bg-slate-800 dark:border-slate-700 px-3 py-2 text-sm focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-blue-500"
                        >
                            <option value="Admin">Administrator (Full Access)</option>
                            <option value="Manager">Manager (Reports & Billing)</option>
                            <option value="Agent">Agent (Meter Readings Only)</option>
                        </select>
                        <p className="mt-2 text-[10px] text-slate-500">Role defines the level of system features the user can access.</p>
                    </div>
                </div>

                <div className="p-4 border-t border-slate-100 dark:border-slate-800 flex justify-end gap-3">
                    <Button type="button" variant="outline" onClick={onCancel}>Cancel</Button>
                    <Button type="submit" disabled={!isFormValid}>Create Account</Button>
                </div>
            </form>
        </Modal>
    );
};

