        ];

        // Defaulters
        const defaulters = db.prepare("SELECT id, customerName as name, customerAccount as account, total as amountDue, CAST(julianday('now') - julianday(dueDate) AS INTEGER) as daysOverdue FROM invoices WHERE status = 'Overdue' ORDER BY amountDue DESC LIMIT 5").all();

        // Recent Payments
        const recentPayments = db.prepare("SELECT * FROM payments ORDER BY date DESC LIMIT 4").all();

