app.get('/api/invoices', (req, res) => {
    const { q, sortKey, sortDir, page = 1, limit = 10, status } = req.query;
    let query = 'SELECT * FROM invoices';
    const params = [];
    const conditions = [];

    if (q) {
        conditions.push('(id LIKE ? OR customerName LIKE ? OR customerAccount LIKE ?)');
        params.push(`%${q}%`, `%${q}%`, `%${q}%`);
    }

    if (status) {
        const statusList = status.split(',');
        conditions.push(`status IN (${statusList.map(() => '?').join(',')})`);
        params.push(...statusList);
    }

    if (conditions.length > 0) {
        query += ' WHERE ' + conditions.join(' AND ');
    }

    if (sortKey && sortDir) {
        query += ` ORDER BY ${sortKey} ${sortDir === 'descending' ? 'DESC' : 'ASC'}`;
    } else {
        query += ' ORDER BY issueDate DESC';
    }

    const totalItemsQuery = query.replace('SELECT *', 'SELECT COUNT(*) as count');
    const totalItems = db.prepare(totalItemsQuery).get(...params).count;

    if (limit !== 'all') {
        query += ' LIMIT ? OFFSET ?';
        params.push(parseInt(limit), (parseInt(page) - 1) * parseInt(limit));
    }

    const invoices = db.prepare(query).all(...params);

    // Attach items to each invoice
    const stmt = db.prepare('SELECT * FROM invoice_items WHERE invoiceId = ?');
    const fullInvoices = invoices.map(inv => ({
        ...inv,
        items: stmt.all(inv.id)
    }));

    res.json({ invoices: fullInvoices, totalItems });
});

app.post('/api/invoices', (req, res) => {
    const { customerId, issueDate, dueDate, items } = req.body;
    try {
        const customer = db.prepare('SELECT * FROM customers WHERE id = ?').get(customerId);
        if (!customer) return res.status(404).json({ message: 'Customer not found' });

        const lastInv = db.prepare("SELECT id FROM invoices ORDER BY id DESC LIMIT 1").get();
        const nextIdNum = lastInv ? parseInt(lastInv.id.split('-')[2]) + 1 : 1001;
        const newInvoiceId = `INV-${new Date().getFullYear()}-${nextIdNum}`;

        const subtotal = items.reduce((sum, item) => sum + item.quantity * item.unitPrice, 0);

        db.transaction(() => {
            db.prepare('INSERT INTO invoices (id, customerName, customerAccount, customerAddress, issueDate, generationDate, dueDate, subtotal, penalties, total, status) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)')
              .run(newInvoiceId, customer.name, customer.accountNumber, customer.address, issueDate, new Date().toISOString().split('T')[0], dueDate, subtotal, 0, subtotal, 'Due');

            const insertItem = db.prepare('INSERT INTO invoice_items (invoiceId, description, quantity, unitPrice, total) VALUES (?, ?, ?, ?, ?)');
            items.forEach(item => insertItem.run(newInvoiceId, item.description, item.quantity, item.unitPrice, item.quantity * item.unitPrice));
        })();

        res.status(201).json({ id: newInvoiceId });
    } catch (err) {
        res.status(500).json({ message: 'Failed to create invoice', error: err.message });
    }
});

app.put('/api/invoices/:id', (req, res) => {
    const { id } = req.params;
    const { customerId, issueDate, dueDate, items, status } = req.body;

    try {
        const invoice = db.prepare('SELECT * FROM invoices WHERE id = ?').get(id);
        if (!invoice) {
            return res.status(404).json({ message: 'Invoice not found' });
        }

        const customer = db.prepare('SELECT * FROM customers WHERE id = ?').get(customerId);
        if (!customer) {
            return res.status(404).json({ message: 'Customer not found' });
        }

        const subtotal = items.reduce((sum, item) => sum + Number(item.quantity) * Number(item.unitPrice), 0);
        const total = subtotal + invoice.penalties; 

        db.transaction(() => {
            db.prepare(`
                UPDATE invoices 
                SET customerName = ?, customerAccount = ?, customerAddress = ?, issueDate = ?, dueDate = ?, subtotal = ?, total = ?, status = ?
                WHERE id = ?
            `).run(customer.name, customer.accountNumber, customer.address, issueDate, dueDate, subtotal, total, status, id);

            db.prepare('DELETE FROM invoice_items WHERE invoiceId = ?').run(id);

            const insertItem = db.prepare('INSERT INTO invoice_items (invoiceId, description, quantity, unitPrice, total) VALUES (?, ?, ?, ?, ?)');
            for (const item of items) {
                const itemTotal = Number(item.quantity) * Number(item.unitPrice);
                insertItem.run(id, item.description, item.quantity, item.unitPrice, itemTotal);
            }
        })();

        res.status(200).json({ message: 'Invoice updated successfully' });
    } catch (err) {
        res.status(500).json({ message: 'Failed to update invoice', error: err.message });
    }
});

app.post('/api/invoices/:id/pay', (req, res) => {
    const { id } = req.params;
    const { method = 'Manual', paymentDate = new Date().toISOString().split('T')[0] } = req.body;

    try {
        const invoice = db.prepare('SELECT * FROM invoices WHERE id = ?').get(id);
        if (!invoice) {
            return res.status(404).json({ message: 'Invoice not found' });
        }
        if (invoice.status === 'Paid') {
            return res.status(400).json({ message: 'Invoice is already paid' });
        }

        db.transaction(() => {
            // Update invoice status
            db.prepare('UPDATE invoices SET status = ? WHERE id = ?').run('Paid', id);

            // Create a payment record
            const newPaymentId = `RPT-${Date.now()}`;
            db.prepare('INSERT INTO payments (id, customerName, amount, method, date, invoiceId) VALUES (?, ?, ?, ?, ?, ?)')
              .run(newPaymentId, invoice.customerName, invoice.total, method, paymentDate, id);
        })();

        res.status(200).json({ message: 'Invoice marked as paid and payment recorded.' });
    } catch (err) {
        res.status(500).json({ message: 'Failed to process payment.', error: err.message });
    }
});


// --- PAYMENTS ---
app.get('/api/payments', (req, res) => {
    const { q, sortKey, sortDir, page = 1, limit = 10 } = req.query;
    let query = 'SELECT * FROM payments';
    const params = [];
    if (q) {
        query += ' WHERE customerName LIKE ? OR invoiceId LIKE ?';
        params.push(`%${q}%`, `%${q}%`);
    }
    if (sortKey && sortDir) {
        query += ` ORDER BY ${sortKey} ${sortDir === 'descending' ? 'DESC' : 'ASC'}`;
    } else {
        query += ' ORDER BY date DESC';
    }
    const totalItems = db.prepare(query.replace('SELECT *', 'SELECT COUNT(*) as count')).get(...params).count;
    query += ' LIMIT ? OFFSET ?';
    params.push(parseInt(limit), (parseInt(page) - 1) * parseInt(limit));
    const payments = db.prepare(query).all(...params);
    res.json({ payments, totalItems });
});

app.post('/api/payments', (req, res) => {
    const { invoiceId, amount, method, date } = req.body;
    try {
        const invoice = db.prepare('SELECT * FROM invoices WHERE id = ?').get(invoiceId);
        if (!invoice) {
            return res.status(404).json({ message: 'Invoice not found' });
        }
        if (invoice.status === 'Paid') {
            return res.status(400).json({ message: 'This invoice has already been paid.' });
        }

        db.transaction(() => {
            // Update invoice status to 'Paid'
            db.prepare('UPDATE invoices SET status = ? WHERE id = ?').run('Paid', invoiceId);

            // Create the payment record
            const newPaymentId = `RPT-${Date.now()}`;
            db.prepare('INSERT INTO payments (id, customerName, amount, method, date, invoiceId) VALUES (?, ?, ?, ?, ?, ?)')
              .run(newPaymentId, invoice.customerName, amount, method, date, invoiceId);
        })();

        res.status(201).json({ message: 'Payment recorded successfully.' });
    } catch (err) {
        res.status(500).json({ message: 'Failed to record payment', error: err.message });
    }
});

// --- SETTINGS ---
app.get('/api/settings/billing', (req, res) => {
    const settings = db.prepare('SELECT * FROM billing_settings WHERE id = 1').get();
    res.json(settings);
});

app.post('/api/settings/billing', (req, res) => {
    const { frequency, generationDay, readingCutoffDays } = req.body;
    db.prepare('UPDATE billing_settings SET frequency = ?, generationDay = ?, readingCutoffDays = ? WHERE id = 1')
      .run(frequency, generationDay, readingCutoffDays);
    res.status(200).json({ message: 'Settings updated' });
});

// --- USERS ---
app.get('/api/users', (req, res) => {
    try {
        const users = db.prepare('SELECT * FROM users ORDER BY name ASC').all();
        res.json(users);
    } catch (err) {
        res.status(500).json({ message: 'Failed to fetch users', error: err.message });
    }
});

app.post('/api/users', (req, res) => {
    const { name, email, role } = req.body;
    try {
        const id = `USR-${Date.now()}`;
        const lastActive = new Date().toISOString();
        db.prepare('INSERT INTO users (id, name, email, role, lastActive) VALUES (?, ?, ?, ?, ?)')
          .run(id, name, email, role, lastActive);
        res.status(201).json({ id, name, email, role, lastActive });
    } catch (err) {
        if (err.message.includes('UNIQUE constraint failed')) {
            return res.status(400).json({ message: 'A user with this email already exists.' });
        }
        res.status(500).json({ message: 'Failed to create user', error: err.message });
    }
});

app.delete('/api/users/:id', (req, res) => {
    try {
        db.prepare('DELETE FROM users WHERE id = ?').run(req.params.id);
        res.status(200).json({ message: 'User deleted' });
    } catch (err) {
        res.status(500).json({ message: 'Failed to delete user', error: err.message });
    }
});

// --- DATABASE VALIDATION ---
app.get('/api/db/validate', (req, res) => {
    try {
        // 1. Run Integrity Check
        const integrityResult = db.prepare('PRAGMA integrity_check').get();
        const isHealthy = integrityResult.integrity_check === 'ok';

        // 2. Gather Statistics
        const stats = {
            customers: db.prepare('SELECT count(*) as count FROM customers').get().count,
            meters: db.prepare('SELECT count(*) as count FROM meters').get().count,
            readings: db.prepare('SELECT count(*) as count FROM meter_readings').get().count,
            invoices: db.prepare('SELECT count(*) as count FROM invoices').get().count,
            payments: db.prepare('SELECT count(*) as count FROM payments').get().count,
            users: db.prepare('SELECT count(*) as count FROM users').get().count,
        };

        // 3. File System Info
        const dbPath = path.join(__dirname, 'db', 'database.sqlite');
        let fileSize = 'Unknown';
        if (fs.existsSync(dbPath)) {
            const fStats = fs.statSync(dbPath);
            fileSize = (fStats.size / 1024).toFixed(2) + ' KB';
        }

        res.json({
            status: isHealthy ? 'Healthy' : 'Corrupted',
            integrityMessage: integrityResult.integrity_check,
            tableCounts: stats,
            size: fileSize,
            lastValidated: new Date().toISOString()
        });
    } catch (err) {
        res.status(500).json({ message: 'Validation failed', error: err.message });
    }
});


app.listen(PORT, () => {
    console.log(`Server is running on http://localhost:${PORT}`);
});

import React, { useState, useEffect } from 'react';
import { BillingSettings } from '../types';
import BillingCycleCard from './BillingCycleCard';
import PdfCustomizationCard from './PdfCustomizationCard';
import DatabaseDiagnostics from './DatabaseDiagnostics';
import { fetchFromApi } from '../lib/api';

interface SettingsProps {
    showToast: (message: string, type?: 'success' | 'error') => void;
}

const Settings: React.FC<SettingsProps> = ({ showToast }) => {
    const [billingSettings, setBillingSettings] = useState<BillingSettings | null>(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchSettings = async () => {
            try {
                const data = await fetchFromApi('settings/billing');
                setBillingSettings(data);
            } catch (err) {
                showToast('Failed to load billing settings.', 'error');
            } finally {
                setLoading(false);
            }
        };
        fetchSettings();
    }, [showToast]);

    const handleSaveBillingSettings = async (newSettings: BillingSettings) => {
        try {
            await fetchFromApi('settings/billing', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(newSettings),
            });
            setBillingSettings(newSettings);
            return true;
        } catch (err) {
            return false;
        }
    };

    return (
        <div className="space-y-8 animate-fade-in-up">
            <div>
                <h2 className="text-2xl font-bold text-gray-900 dark:text-white">System Settings</h2>
                <p className="mt-1 text-sm text-gray-500 dark:text-gray-400">
                    Manage system-wide configurations and preferences.
                </p>
            </div>

            {loading ? (
                <div className="flex items-center gap-3 text-slate-500 italic">
                    <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
                    Loading settings...
                </div>
            ) : billingSettings ? (
                <div className="space-y-8">
                    <BillingCycleCard 
                        settings={billingSettings} 
                        onSave={handleSaveBillingSettings} 
                        showToast={showToast}
                    />

                    <DatabaseDiagnostics showToast={showToast} />

                    <PdfCustomizationCard showToast={showToast} />
                </div>
            ) : (
                <p className="text-red-500">Could not load billing settings.</p>
            )}
        </div>
    );
};

export default Settings;

import React, { useState, useEffect, useCallback } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from './ui/Card';
import { Button } from './ui/Button';
import { ShieldCheckIcon, AlertTriangleIcon, LayoutGridIcon, ActivityIcon, ZapIcon, DownloadIcon } from './icons';
import { fetchFromApi } from '../lib/api';

interface DbStats {
    status: 'Healthy' | 'Corrupted';
    integrityMessage: string;
    tableCounts: {
        customers: number;
        meters: number;
        readings: number;
        invoices: number;
        payments: number;
        users: number;
    };
    size: string;
    lastValidated: string;
}

const DatabaseDiagnostics: React.FC<{ showToast: (msg: string, type?: 'success' | 'error') => void }> = ({ showToast }) => {
    const [stats, setStats] = useState<DbStats | null>(null);
    const [isValidating, setIsValidating] = useState(false);

    const runValidation = useCallback(async () => {
        setIsValidating(true);
        try {
            const data = await fetchFromApi('db/validate');
            setStats(data);
            if (data.status === 'Healthy') {
                showToast('Database integrity check passed.', 'success');
            } else {
                showToast('Warning: Database integrity issues detected!', 'error');
            }
        } catch (err: any) {
            showToast(err.message || 'Validation failed.', 'error');
        } finally {
            setIsValidating(false);
        }
    }, [showToast]);

    useEffect(() => {
        runValidation();
    }, []);

    const StatItem = ({ label, count, icon: Icon }: any) => (
        <div className="bg-slate-50 dark:bg-slate-800/40 p-4 rounded-xl border border-slate-100 dark:border-slate-800 transition-all hover:shadow-md">
            <div className="flex items-center gap-3 mb-1">
                <div className="p-1.5 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
                    <Icon className="w-4 h-4 text-blue-600 dark:text-blue-400" />
                </div>
                <span className="text-xs font-bold text-slate-500 uppercase tracking-wider">{label}</span>
            </div>
            <p className="text-2xl font-black text-slate-900 dark:text-white">
                {count?.toLocaleString() || 0}
            </p>
        </div>
    );

    return (
        <Card className="overflow-hidden border-slate-200 dark:border-slate-800 shadow-xl">
            <CardHeader className="bg-slate-50/50 dark:bg-slate-800/20">
                <div className="flex flex-col md:flex-row justify-between md:items-center gap-4">
                    <div>
                        <CardTitle className="flex items-center gap-2">
                            <ActivityIcon className="w-5 h-5 text-indigo-500" />
                            Database Health & Diagnostics
                        </CardTitle>
                        <CardDescription>Monitor data integrity and record distribution across the system.</CardDescription>
                    </div>
                    <Button 
                        onClick={runValidation} 
                        disabled={isValidating}
                        variant={stats?.status === 'Corrupted' ? 'destructive' : 'outline'}
                    >
                        {isValidating ? (
                            <>
                                <svg className="animate-spin -ml-1 mr-3 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                                </svg>
                                Analyzing...
                            </>
                        ) : (
                            <>
                                <ZapIcon className="w-4 h-4 mr-2" />
                                Run Full Diagnostic
                            </>
                        )}
                    </Button>
                </div>
            </CardHeader>
            <CardContent className="p-6">
                <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
                    {/* Status Summary */}
                    <div className="lg:col-span-4 space-y-6">
                        <div className={`p-6 rounded-2xl border-2 flex flex-col items-center text-center space-y-3 ${
                            stats?.status === 'Healthy' 
                            ? 'bg-emerald-50/50 border-emerald-100 dark:bg-emerald-900/10 dark:border-emerald-900/30' 
                            : 'bg-rose-50 border-rose-100 dark:bg-rose-900/10 dark:border-rose-900/30'
                        }`}>
                            {stats?.status === 'Healthy' ? (
                                <div className="relative">
                                    <div className="absolute inset-0 bg-emerald-500 rounded-full animate-ping opacity-20"></div>
                                    <ShieldCheckIcon className="w-12 h-12 text-emerald-500 relative" />
                                </div>
                            ) : (
                                <AlertTriangleIcon className="w-12 h-12 text-rose-500" />
                            )}
                            <div>
                                <h4 className="text-xl font-bold">Storage is {stats?.status || 'Unknown'}</h4>
                                <p className="text-sm text-slate-500 dark:text-slate-400">
                                    {stats?.status === 'Healthy' 
                                        ? 'Integrity check passed. No corruption detected.' 
                                        : 'Critical system error: Database corruption detected!'}
                                </p>
                            </div>
                            <div className="pt-2 text-[10px] uppercase font-bold text-slate-400 tracking-widest">
                                Last Check: {stats?.lastValidated ? new Date(stats.lastValidated).toLocaleTimeString() : 'Never'}
                            </div>
                        </div>

                        <div className="bg-slate-100 dark:bg-slate-800/50 p-4 rounded-xl space-y-3">
                            <div className="flex justify-between text-sm">
                                <span className="text-slate-500">Engine</span>
                                <span className="font-mono font-bold">SQLite 3.x (B-Tree)</span>
                            </div>
                            <div className="flex justify-between text-sm">
                                <span className="text-slate-500">File Size</span>
                                <span className="font-mono font-bold">{stats?.size || '0 KB'}</span>
                            </div>
                             <div className="flex justify-between text-sm">
                                <span className="text-slate-500">Status Msg</span>
                                <span className="font-mono text-xs text-emerald-600 dark:text-emerald-400 truncate max-w-[120px]">{stats?.integrityMessage || 'ok'}</span>
                            </div>
                        </div>
                    </div>

                    {/* Table Distribution */}
                    <div className="lg:col-span-8">
                        <div className="flex items-center gap-2 mb-4">
                            <LayoutGridIcon className="w-4 h-4 text-slate-400" />
                            <h4 className="text-sm font-bold uppercase tracking-widest text-slate-500">Record Distribution</h4>
                        </div>
                        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                            <StatItem label="Customers" count={stats?.tableCounts.customers} icon={ShieldCheckIcon} />
                            <StatItem label="Meters" count={stats?.tableCounts.meters} icon={ActivityIcon} />
                            <StatItem label="Readings" count={stats?.tableCounts.readings} icon={ZapIcon} />
                            <StatItem label="Invoices" count={stats?.tableCounts.invoices} icon={DownloadIcon} />
                            <StatItem label="Payments" count={stats?.tableCounts.payments} icon={ZapIcon} />
                            <StatItem label="Staff Users" count={stats?.tableCounts.users} icon={ShieldCheckIcon} />
                        </div>

                        <div className="mt-8 p-4 bg-amber-50 dark:bg-amber-900/10 border border-amber-100 dark:border-amber-900/30 rounded-xl">
                            <p className="text-xs text-amber-700 dark:text-amber-400 flex items-start gap-2">
                                <AlertTriangleIcon className="w-4 h-4 flex-shrink-0 mt-0.5" />
                                <span><b>Maintenance Tip:</b> If your database exceeds 1GB or record counts go above 100k, consider enabling Write-Ahead Logging (WAL) mode or transitioning to a cloud database like PostgreSQL for better concurrency.</span>
                            </p>
                        </div>
                    </div>
                </div>
            </CardContent>
        </Card>
    );
};

export default DatabaseDiagnostics;

