const express = require('express');
const cors = require('cors');
const db = require('./db');
const path = require('path');
const fs = require('fs');

const app = express();
const PORT = 3001;

app.use(cors());
app.use(express.json());

// --- DASHBOARD ---
app.get('/api/dashboard', (req, res) => {
    try {
        // KPIs
        const totalBilled = db.prepare("SELECT SUM(total) as value FROM invoices WHERE issueDate >= date('now', '-30 days')").get().value || 0;
        const totalCollected = db.prepare("SELECT SUM(amount) as value FROM payments WHERE date >= date('now', '-30 days')").get().value || 0;
        const activeCustomers = db.prepare("SELECT count(*) as value FROM customers").get().value || 0;
        const overdueAccounts = db.prepare("SELECT count(*) as value FROM invoices WHERE status = 'Overdue'").get().value || 0;

        // Revenue Chart (last 6 months)
        const revenueData = db.prepare(`
            WITH RECURSIVE months(m) AS (
                SELECT date('now', 'start of month')
                UNION ALL
                SELECT date(m, '-1 month') FROM months WHERE m > date('now', 'start of month', '-5 months')
            )
            SELECT
                strftime('%b', m) as month,
                (SELECT IFNULL(SUM(total), 0) FROM invoices WHERE strftime('%Y-%m', issueDate) = strftime('%Y-%m', m)) as billed,
                (SELECT IFNULL(SUM(amount), 0) FROM payments WHERE strftime('%Y-%m', date) = strftime('%Y-%m', m)) as collected
            FROM months ORDER BY m ASC
        `).all();

        // Debt Aging
        const agingData = [
            { name: '0-30 Days', value: db.prepare("SELECT SUM(total) as v FROM invoices WHERE status = 'Due' AND dueDate >= date('now', '-30 days')").get().v || 0, fill: '#3b82f6' },
            { name: '31-60 Days', value: db.prepare("SELECT SUM(total) as v FROM invoices WHERE status = 'Overdue' AND dueDate BETWEEN date('now', '-60 days') AND date('now', '-31 days')").get().v || 0, fill: '#f59e0b' },
            { name: '61-90 Days', value: db.prepare("SELECT SUM(total) as v FROM invoices WHERE status = 'Overdue' AND dueDate BETWEEN date('now', '-90 days') AND date('now', '-61 days')").get().v || 0, fill: '#ef4444' },
            { name: '90+ Days', value: db.prepare("SELECT SUM(total) as v FROM invoices WHERE status = 'Overdue' AND dueDate < date('now', '-90 days')").get().v || 0, fill: '#7f1d1d' },
        ];

        // Defaulters
        const defaulters = db.prepare("SELECT id, customerName as name, customerAccount as account, total as amountDue, CAST(julianday('now') - julianday(dueDate) AS INTEGER) as daysOverdue FROM invoices WHERE status = 'Overdue' ORDER BY amountDue DESC LIMIT 5").all();

        // Recent Payments
        const recentPayments = db.prepare("SELECT * FROM payments ORDER BY date DESC LIMIT 4").all();

        res.json({
            kpiData: [
                { title: 'Total Billed (Month)', value: `KES ${totalBilled.toLocaleString()}`, change: '+5.2%', changeType: 'increase' },
                { title: 'Total Collected (Month)', value: `KES ${totalCollected.toLocaleString()}`, change: '+8.1%', changeType: 'increase' },
                { title: 'Active Customers', value: activeCustomers.toLocaleString(), change: '+25', changeType: 'increase' },
                { title: 'Overdue Accounts', value: overdueAccounts.toLocaleString(), change: '-3.4%', changeType: 'decrease' },
            ],
            revenueData,
            agingData,
            defaulters,
            recentPayments,
            // NRW data is static for now as it requires more complex inputs
            nrwData: [
                { day: 'Mon', percentage: 18.5 }, { day: 'Tue', percentage: 19.2 }, { day: 'Wed', percentage: 17.8 },
                { day: 'Thu', percentage: 20.1 }, { day: 'Fri', percentage: 19.5 }, { day: 'Sat', percentage: 21.3 }, { day: 'Sun', percentage: 20.8 },
            ]
        });

    } catch (error) {
        res.status(500).json({ message: 'Failed to fetch dashboard data', error: error.message });
    }
});


// --- CUSTOMERS ---
app.get('/api/customers', (req, res) => {
    const { q, sortKey, sortDir, page = 1, limit = 10 } = req.query;
    let query = 'SELECT * FROM customers';
    const params = [];

    if (q) {
        query += ' WHERE name LIKE ? OR accountNumber LIKE ? OR email LIKE ?';
        params.push(`%${q}%`, `%${q}%`, `%${q}%`);
    }

    if (sortKey && sortDir) {
        const allowedKeys = ['name', 'accountNumber', 'email', 'address', 'joinDate'];
        if (allowedKeys.includes(sortKey)) {
            query += ` ORDER BY ${sortKey} ${sortDir === 'descending' ? 'DESC' : 'ASC'}`;
        }
    } else {
         query += ` ORDER BY joinDate DESC`;
    }

    const totalStmt = db.prepare(query.replace('SELECT *', 'SELECT COUNT(*) as count')).all(...params);
    const totalItems = totalStmt[0].count;

    if (limit !== '1000') {
        query += ' LIMIT ? OFFSET ?';
        params.push(parseInt(limit), (parseInt(page) - 1) * parseInt(limit));
    }

    const customers = db.prepare(query).all(...params);
    res.json({ customers, totalItems });
});

app.get('/api/customers/:id', (req, res) => {
    try {
        const customer = db.prepare('SELECT * FROM customers WHERE id = ?').get(req.params.id);
        if (!customer) {
            return res.status(404).json({ message: 'Customer not found' });
        }

        const invoices = db.prepare('SELECT * FROM invoices WHERE customerAccount = ? ORDER BY issueDate DESC').all(customer.accountNumber);
        const payments = db.prepare('SELECT * FROM payments WHERE customerName = ? ORDER BY date DESC').all(customer.name);
        const meters = db.prepare('SELECT * FROM meters WHERE customerAccount = ?').all(customer.accountNumber);

        const balanceResult = db.prepare("SELECT SUM(total) as totalDue FROM invoices WHERE customerAccount = ? AND status IN ('Due', 'Overdue')").get(customer.accountNumber);
        const outstandingBalance = balanceResult.totalDue || 0;

        res.json({ 
            customer, 
            history: { invoices, payments },
            meters,
            outstandingBalance,
            lastUpdated: new Date().toISOString(),
        });

    } catch (err) {
        res.status(500).json({ message: 'Failed to fetch customer details', error: err.message });
    }
});


app.post('/api/customers', (req, res) => {
    try {
        const { name, email, phone, address } = req.body;
