            id: `CUST-${Date.now()}`,
            accountNumber: `ACC-${nextIdNum}`,
            name, email, phone, address, joinDate
        };
        db.prepare('INSERT INTO customers (id, accountNumber, name, email, phone, address, joinDate) VALUES (@id, @accountNumber, @name, @email, @phone, @address, @joinDate)').run(newCustomer);
        res.status(201).json(newCustomer);
    } catch (err) {
        res.status(500).json({ message: 'Failed to create customer', error: err.message });
