        if (!meter) return res.status(404).json({ message: 'Meter not found' });

        if (status && status !== meter.status) {
            db.prepare('INSERT INTO meter_status_history (meterId, date, fromStatus, toStatus) VALUES (?, ?, ?, ?)')
              .run(req.params.id, new Date().toISOString().split('T')[0], meter.status, status);
        }

        const result = db.prepare('UPDATE meters SET status = ?, customerAccount = ? WHERE id = ?')
                         .run(status || meter.status, customerAccount !== undefined ? customerAccount : meter.customerAccount, req.params.id);

        if (result.changes > 0) {
            res.status(200).json({ message: 'Meter updated' });
        } else {
            res.status(404).json({ message: 'Meter not found' });
