app.get('/api/db/validate', (req, res) => {
    try {
        // 1. Run Integrity Check
        const integrityResult = db.prepare('PRAGMA integrity_check').get();
        const isHealthy = integrityResult.integrity_check === 'ok';

        // 2. Gather Statistics
        const stats = {
            customers: db.prepare('SELECT count(*) as count FROM customers').get().count,
            meters: db.prepare('SELECT count(*) as count FROM meters').get().count,
            readings: db.prepare('SELECT count(*) as count FROM meter_readings').get().count,
            invoices: db.prepare('SELECT count(*) as count FROM invoices').get().count,
            payments: db.prepare('SELECT count(*) as count FROM payments').get().count,
            users: db.prepare('SELECT count(*) as count FROM users').get().count,
        };

        // 3. File System Info
        const dbPath = path.join(__dirname, 'db', 'database.sqlite');
        let fileSize = 'Unknown';
        if (fs.existsSync(dbPath)) {
            const fStats = fs.statSync(dbPath);
            fileSize = (fStats.size / 1024).toFixed(2) + ' KB';
        }

        res.json({
            status: isHealthy ? 'Healthy' : 'Corrupted',
            integrityMessage: integrityResult.integrity_check,
            tableCounts: stats,
            size: fileSize,
            lastValidated: new Date().toISOString()
        });
    } catch (err) {
        res.status(500).json({ message: 'Validation failed', error: err.message });
    }
});


