            )
            SELECT
                strftime('%b', m) as month,
                (SELECT IFNULL(SUM(total), 0) FROM invoices WHERE strftime('%Y-%m', issueDate) = strftime('%Y-%m', m)) as billed,
                (SELECT IFNULL(SUM(amount), 0) FROM payments WHERE strftime('%Y-%m', date) = strftime('%Y-%m', m)) as collected
