// --- CUSTOMERS ---
app.get('/api/customers', (req, res) => {
    try {
        const { q, sortKey, sortDir, page = 1, limit = 10 } = req.query;
        let query = 'SELECT * FROM customers';
        const params = [];

        if (q) {
            query += ' WHERE name LIKE ? OR accountNumber LIKE ? OR email LIKE ?';
            params.push(`%${q}%`, `%${q}%`, `%${q}%`);
        }

        if (sortKey && sortDir) {
            const allowedKeys = ['name', 'accountNumber', 'email', 'address', 'joinDate'];
            if (allowedKeys.includes(sortKey)) {
                query += ` ORDER BY ${sortKey} ${sortDir === 'descending' ? 'DESC' : 'ASC'}`;
            }
        } else {
             query += ` ORDER BY joinDate DESC`;
        }

        // Calculate totals for pagination
        const totalQuery = q 
            ? 'SELECT COUNT(*) as count FROM customers WHERE name LIKE ? OR accountNumber LIKE ? OR email LIKE ?'
            : 'SELECT COUNT(*) as count FROM customers';
        const totalParams = q ? [`%${q}%`, `%${q}%`, `%${q}%`] : [];
        const totalItems = db.prepare(totalQuery).get(...totalParams).count;

        // Apply pagination
        if (limit !== '1000' && limit !== 'all') {
            const parsedLimit = Math.max(1, parseInt(limit) || 10);
            const parsedPage = Math.max(1, parseInt(page) || 1);
            query += ' LIMIT ? OFFSET ?';
            params.push(parsedLimit, (parsedPage - 1) * parsedLimit);
        }

        const customers = db.prepare(query).all(...params);
        res.json({ customers, totalItems });
    } catch (error) {
        console.error('Customer fetch error:', error);
        res.status(500).json({ message: 'Failed to fetch customers', error: error.message });
    }
});

