    const newMeterId = `M-${Date.now()}`;
    const newReadingId = `R-${Date.now()}`;
    try {
        db.transaction(() => {
            db.prepare('INSERT INTO meters (id, serialNumber, customerAccount, status, installationDate) VALUES (?, ?, ?, ?, ?)')
              .run(newMeterId, serialNumber, customerAccount || null, 'Active', installationDate);
            db.prepare('INSERT INTO meter_readings (id, meterId, reading, date) VALUES (?, ?, ?, ?)')
              .run(newReadingId, newMeterId, initialReading, installationDate);
        })();
        res.status(201).json({ id: newMeterId });
    } catch (err) {
        res.status(500).json({ message: 'Failed to add meter', error: err.message });
    }
});

app.put('/api/meters/:id', (req, res) => {
    const { status, customerAccount } = req.body; // Can be used to update status or assign customer
    try {
        const meter = db.prepare('SELECT * FROM meters WHERE id = ?').get(req.params.id);
        if (!meter) return res.status(404).json({ message: 'Meter not found' });

        if (status && status !== meter.status) {
            db.prepare('INSERT INTO meter_status_history (meterId, date, fromStatus, toStatus) VALUES (?, ?, ?, ?)')
              .run(req.params.id, new Date().toISOString().split('T')[0], meter.status, status);
        }

        const result = db.prepare('UPDATE meters SET status = ?, customerAccount = ? WHERE id = ?')
                         .run(status || meter.status, customerAccount !== undefined ? customerAccount : meter.customerAccount, req.params.id);

        if (result.changes > 0) {
            res.status(200).json({ message: 'Meter updated' });
        } else {
            res.status(404).json({ message: 'Meter not found' });
        }
    } catch (err) {
        res.status(500).json({ message: 'Failed to update meter', error: err.message });
    }
});

