        const params = [];
        const conditions = [];

        if (q) {
            conditions.push('(id LIKE ? OR customerName LIKE ? OR customerAccount LIKE ?)');
            params.push(`%${q}%`, `%${q}%`, `%${q}%`);
        }

        if (status) {
            const statusList = status.split(',');
            conditions.push(`status IN (${statusList.map(() => '?').join(',')})`);
            params.push(...statusList);
        }

        if (conditions.length > 0) {
            query += ' WHERE ' + conditions.join(' AND ');
        }

        if (sortKey && sortDir) {
            query += ` ORDER BY ${sortKey} ${sortDir === 'descending' ? 'DESC' : 'ASC'}`;
        } else {
            query += ' ORDER BY issueDate DESC';
        }

        const totalItemsQuery = query.replace('SELECT *', 'SELECT COUNT(*) as count');
        const totalItems = db.prepare(totalItemsQuery).get(...params).count;

        if (limit !== 'all') {
            const parsedLimit = Math.max(1, parseInt(limit) || 10);
            const parsedPage = Math.max(1, parseInt(page) || 1);
            query += ' LIMIT ? OFFSET ?';
            params.push(parsedLimit, (parsedPage - 1) * parsedLimit);
