app.post('/api/invoices', (req, res) => {
    const { customerId, issueDate, dueDate, items } = req.body;
    try {
        const customer = db.prepare('SELECT * FROM customers WHERE id = ?').get(customerId);
        if (!customer) return res.status(404).json({ message: 'Customer not found' });

        const lastInv = db.prepare("SELECT id FROM invoices ORDER BY id DESC LIMIT 1").get();
        const nextIdNum = lastInv ? parseInt(lastInv.id.split('-')[2]) + 1 : 1001;
        const newInvoiceId = `INV-${new Date().getFullYear()}-${nextIdNum}`;

        const subtotal = items.reduce((sum, item) => sum + item.quantity * item.unitPrice, 0);

        db.transaction(() => {
            db.prepare('INSERT INTO invoices (id, customerName, customerAccount, customerAddress, issueDate, generationDate, dueDate, subtotal, penalties, total, status) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)')
              .run(newInvoiceId, customer.name, customer.accountNumber, customer.address, issueDate, new Date().toISOString().split('T')[0], dueDate, subtotal, 0, subtotal, 'Due');

            const insertItem = db.prepare('INSERT INTO invoice_items (invoiceId, description, quantity, unitPrice, total) VALUES (?, ?, ?, ?, ?)');
            items.forEach(item => insertItem.run(newInvoiceId, item.description, item.quantity, item.unitPrice, item.quantity * item.unitPrice));
        })();

        res.status(201).json({ id: newInvoiceId });
    } catch (err) {
        res.status(500).json({ message: 'Failed to create invoice', error: err.message });
    }
});

// Bulk billing preview
app.get('/api/invoices/bulk/preview', (req, res) => {
    try {
        // Find customers with meters and at least one reading
        const billable = db.prepare(`
            SELECT 
                c.id as customerId, c.name, c.accountNumber, c.address,
                m.id as meterId, m.serialNumber,
                (SELECT reading FROM meter_readings WHERE meterId = m.id ORDER BY date DESC LIMIT 1) as currentReading,
                (SELECT date FROM meter_readings WHERE meterId = m.id ORDER BY date DESC LIMIT 1) as readingDate,
                (SELECT MAX(issueDate) FROM invoices WHERE customerAccount = c.accountNumber) as lastInvoiceDate
            FROM customers c
            JOIN meters m ON m.customerAccount = c.accountNumber
            WHERE currentReading IS NOT NULL
        `).all();

        // Calculate expected consumption based on last invoice or initial reading
        const preview = billable.map(item => {
            let prevReading = 0;
            if (item.lastInvoiceDate) {
                // Get reading closest to last invoice
                const r = db.prepare("SELECT reading FROM meter_readings WHERE meterId = ? AND date <= ? ORDER BY date DESC LIMIT 1")
                           .get(item.meterId, item.lastInvoiceDate);
                prevReading = r ? r.reading : 0;
            } else {
                // Get first reading
                const r = db.prepare("SELECT reading FROM meter_readings WHERE meterId = ? ORDER BY date ASC LIMIT 1")
                           .get(item.meterId);
                prevReading = r ? r.reading : 0;
            }

            const consumption = Math.max(0, item.currentReading - prevReading);
            return {
                ...item,
                previousReading: prevReading,
                consumption,
                total: consumption * 110 + 200 + 150 // Standard rate: 110/unit + standing + sewer
            };
        });

        res.json(preview);
    } catch (err) {
        res.status(500).json({ message: 'Failed to generate bulk preview', error: err.message });
    }
});

app.post('/api/invoices/bulk/generate', (req, res) => {
    const { batch, issueDate, dueDate, unitPrice = 110 } = req.body;
    try {
        const results = [];
        db.transaction(() => {
            for (const item of batch) {
                const lastInv = db.prepare("SELECT id FROM invoices ORDER BY id DESC LIMIT 1").get();
                const nextIdNum = lastInv ? parseInt(lastInv.id.split('-')[2]) + 1 : 1001;
                const newInvoiceId = `INV-${new Date().getFullYear()}-${nextIdNum}`;

                const standingCharge = 200;
                const sewerCharge = 150;
                const waterTotal = item.consumption * unitPrice;
                const total = waterTotal + standingCharge + sewerCharge;

                db.prepare('INSERT INTO invoices (id, customerName, customerAccount, customerAddress, issueDate, generationDate, dueDate, subtotal, penalties, total, status) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)')
                  .run(newInvoiceId, item.name, item.accountNumber, item.address, issueDate, new Date().toISOString().split('T')[0], dueDate, total, 0, total, 'Due');

                const insertItem = db.prepare('INSERT INTO invoice_items (invoiceId, description, quantity, unitPrice, total) VALUES (?, ?, ?, ?, ?)');
                insertItem.run(newInvoiceId, `Water Usage (${item.consumption} m³)`, item.consumption, unitPrice, waterTotal);
                insertItem.run(newInvoiceId, 'Standing Charge', 1, standingCharge, standingCharge);
                insertItem.run(newInvoiceId, 'Sewerage Charge', 1, sewerCharge, sewerCharge);

                results.push(newInvoiceId);
            }
        })();
        res.status(201).json({ count: results.length, ids: results });
    } catch (err) {
        res.status(500).json({ message: 'Bulk generation failed', error: err.message });
    }
});

app.put('/api/invoices/:id', (req, res) => {
    const { id } = req.params;
    const { customerId, issueDate, dueDate, items, status } = req.body;

    try {
        const invoice = db.prepare('SELECT * FROM invoices WHERE id = ?').get(id);
        if (!invoice) {
            return res.status(404).json({ message: 'Invoice not found' });
        }

        const customer = db.prepare('SELECT * FROM customers WHERE id = ?').get(customerId);
        if (!customer) {
            return res.status(404).json({ message: 'Customer not found' });
        }

        const subtotal = items.reduce((sum, item) => sum + Number(item.quantity) * Number(item.unitPrice), 0);
        const total = subtotal + invoice.penalties; 

        db.transaction(() => {
            db.prepare(`
                UPDATE invoices 
                SET customerName = ?, customerAccount = ?, customerAddress = ?, issueDate = ?, dueDate = ?, subtotal = ?, total = ?, status = ?
                WHERE id = ?
            `).run(customer.name, customer.accountNumber, customer.address, issueDate, dueDate, subtotal, total, status, id);

            db.prepare('DELETE FROM invoice_items WHERE invoiceId = ?').run(id);

            const insertItem = db.prepare('INSERT INTO invoice_items (invoiceId, description, quantity, unitPrice, total) VALUES (?, ?, ?, ?, ?)');
            for (const item of items) {
                const itemTotal = Number(item.quantity) * Number(item.unitPrice);
                insertItem.run(id, item.description, item.quantity, item.unitPrice, itemTotal);
            }
        })();

        res.status(200).json({ message: 'Invoice updated successfully' });
    } catch (err) {
        res.status(500).json({ message: 'Failed to update invoice', error: err.message });
    }
});

app.post('/api/invoices/:id/pay', (req, res) => {
    const { id } = req.params;
    const { method = 'Manual', paymentDate = new Date().toISOString().split('T')[0] } = req.body;

    try {
        const invoice = db.prepare('SELECT * FROM invoices WHERE id = ?').get(id);
        if (!invoice) {
            return res.status(404).json({ message: 'Invoice not found' });
        }
        if (invoice.status === 'Paid') {
            return res.status(400).json({ message: 'Invoice is already paid' });
        }

        db.transaction(() => {
            // Update invoice status
            db.prepare('UPDATE invoices SET status = ? WHERE id = ?').run('Paid', id);

            // Create a payment record
            const newPaymentId = `RPT-${Date.now()}`;
            db.prepare('INSERT INTO payments (id, customerName, amount, method, date, invoiceId) VALUES (?, ?, ?, ?, ?, ?)')
              .run(newPaymentId, invoice.customerName, invoice.total, method, paymentDate, id);
        })();

        res.status(200).json({ message: 'Invoice marked as paid and payment recorded.' });
    } catch (err) {
        res.status(500).json({ message: 'Failed to process payment.', error: err.message });
    }
});


// --- PAYMENTS ---
app.get('/api/payments', (req, res) => {
    try {
        const { q, sortKey, sortDir, page = 1, limit = 10 } = req.query;
        let query = 'SELECT * FROM payments';
        const params = [];
        if (q) {
            query += ' WHERE customerName LIKE ? OR invoiceId LIKE ?';
            params.push(`%${q}%`, `%${q}%`);
        }
        if (sortKey && sortDir) {
            query += ` ORDER BY ${sortKey} ${sortDir === 'descending' ? 'DESC' : 'ASC'}`;
        } else {
            query += ' ORDER BY date DESC';
        }
        const totalItemsQuery = query.replace('SELECT *', 'SELECT COUNT(*) as count');
        const totalItems = db.prepare(totalItemsQuery).get(...params).count;

        if (limit !== 'all') {
            const parsedLimit = Math.max(1, parseInt(limit) || 10);
            const parsedPage = Math.max(1, parseInt(page) || 1);
            query += ' LIMIT ? OFFSET ?';
            params.push(parsedLimit, (parsedPage - 1) * parsedLimit);
        }
        const payments = db.prepare(query).all(...params);
        res.json({ payments, totalItems });
    } catch (error) {
        res.status(500).json({ message: 'Failed to fetch payments', error: error.message });
    }
});

app.post('/api/payments', (req, res) => {
    const { invoiceId, amount, method, date } = req.body;
    try {
        const invoice = db.prepare('SELECT * FROM invoices WHERE id = ?').get(invoiceId);
        if (!invoice) {
            return res.status(404).json({ message: 'Invoice not found' });
        }
        if (invoice.status === 'Paid') {
            return res.status(400).json({ message: 'This invoice has already been paid.' });
        }

        db.transaction(() => {
            // Update invoice status to 'Paid'
            db.prepare('UPDATE invoices SET status = ? WHERE id = ?').run('Paid', invoiceId);

            // Create the payment record
            const newPaymentId = `RPT-${Date.now()}`;
            db.prepare('INSERT INTO payments (id, customerName, amount, method, date, invoiceId) VALUES (?, ?, ?, ?, ?, ?)')
              .run(newPaymentId, invoice.customerName, amount, method, date, invoiceId);
        })();

        res.status(201).json({ message: 'Payment recorded successfully.' });
    } catch (err) {
        res.status(500).json({ message: 'Failed to record payment', error: err.message });
    }
});

